return this.getUniqueSearchResultItems(items).map((hitItem: SearchResult): SearchResultItem => {
  const content = hitItem._snippetResult.content;
  const hierarchy = hitItem._snippetResult.hierarchy;
  const category = hitItem.hierarchy?.lvl0 ?? null;

  const lvl1Value = hierarchy?.lvl1?.value || hitItem.hierarchy?.lvl1;

  const sublabelSnippet = this.getBestSnippetForMatch(hitItem);

  // If no lvl1, promote sublabel to label to avoid empty titles
  const label = lvl1Value || sublabelSnippet || '';

  const hasSubLabel = lvl1Value && (hierarchy?.lvl2 || hierarchy?.lvl3 || hierarchy?.lvl4);

  return {
    id: hitItem.objectID,
    type: hitItem.hierarchy.lvl0 === 'Tutorials' ? 'code' : 'doc',
    url: hitItem.url,

    labelHtml: this.parseLabelToHtml(label),
    subLabelHtml: this.parseLabelToHtml(hasSubLabel ? sublabelSnippet : null),
    contentHtml: content ? this.parseLabelToHtml(content.value) : null,
    package: category === 'Reference' ? extractPackageNameFromUrl(hitItem.url) : null,

    category: hitItem.hierarchy?.lvl0 ?? null,
  };
});

this.router.events
      .pipe(
        filter((e): e is Scroll => e instanceof Scroll),
        tap((e) => {
          this.cancelScroll?.();
          this.canScroll = true;
          this._lastScrollEvent = e;
        }),
        filter(() => {
          const info = this.router.lastSuccessfulNavigation()?.extras.info as Record<
            'disableScrolling',
            boolean
          >;
          return !info?.['disableScrolling'];
        }),
        switchMap((e) => {
          return firstValueFrom(
            this.appRef.isStable.pipe(
              filter((stable) => stable),
              map(() => e),
            ),
          );
        }),
      )
      .subscribe(() => {
        this.scroll();
      });

return this.apiReferenceManager
      .apiGroups()
      .map((group) => ({
        title: group.title,
        id: group.id,
        items: group.items.filter((apiItem) => {
          return (
            (query == ''
              ? true
              : apiItem.title.toLocaleLowerCase().includes(query) ||
                group.title.toLocaleLowerCase().includes(query)) &&
            (type === ALL_TYPES_KEY || apiItem.itemType === type) &&
            ((status & STATUSES.stable &&
              !apiItem.developerPreview &&
              !apiItem.deprecated &&
              !apiItem.experimental) ||
              (status & STATUSES.deprecated && apiItem.deprecated) ||
              (status & STATUSES.developerPreview && apiItem.developerPreview) ||
              (status & STATUSES.experimental && apiItem.experimental))
          );
        }),
      }))
      .filter(
        (group) =>
          group.items.length > 0 &&
          (this.form.selectedPackage().value() === ALL_PACKAGES ||
            group.id === this.form.selectedPackage().value()),
      );

const getPreview = (propData: TerminalType | CompositeType, isGetterOrSetter: boolean) => {
  if (propData.containerType === 'ReadonlySignal') {
    const {error, value} = safelyReadSignalValue(propData.prop);
    if (error) {
      return `Signal(⚠️ Error)${error.message ? `: ${error.message}` : ''}`;
    }
    return `Readonly Signal(${typeToDescriptorPreview[propData.type](value)})`;
  } else if (propData.containerType === 'WritableSignal') {
    const {error, value} = safelyReadSignalValue(propData.prop);
    if (error) {
      return `Signal(⚠️ Error)${error.message ? `: ${error.message}` : ''}`;
    }
    return `Signal(${typeToDescriptorPreview[propData.type](value)})`;
  }

  return !isGetterOrSetter
    ? typeToDescriptorPreview[propData.type](propData.prop)
    : typeToDescriptorPreview[PropType.Function]({name: ''});
};

try {
  const textToCopy =
    typeof item.value === 'string' ? item.value : JSON.stringify(item.value, null, 2);

  this.clipboard.copy(textToCopy);

  this.transferStateItems.update((items) =>
    items.map((i) => (i.key === item.key ? {...i, isCopied: true} : i)),
  );

  setTimeout(() => {
    this.transferStateItems.update((items) =>
      items.map((i) => (i.key === item.key ? {...i, isCopied: false} : i)),
    );
  }, COPY_FEEDBACK_TIMEOUT);
} catch (err) {
  const message = 'Failed to copy to clipboard';
  const errorDetail =
    err instanceof Error ? `${err.name}: ${err.message}` : JSON.stringify(err);

  this.snackBar.open(message, 'Dismiss', {duration: 3000, horizontalPosition: 'left'});
  this.messageBus.emit('log', [{level: 'error', message: `${message}: ${errorDetail}`}]);
}

return this.driver
      .executeScript('1+1')
      .then((_) => this.driver.logs('performance'))
      .then((entries) => {
        const events: PerfLogEvent[] = [];
        entries.forEach((entry: any) => {
          const message = (
            JSON.parse(entry['message']) as {message: {method: string; params: PerfLogEvent}}
          )['message'];
          if (message['method'] === 'Tracing.dataCollected') {
            events.push(message['params']);
          }
          if (message['method'] === 'Tracing.bufferUsage') {
            throw new Error('The DevTools trace buffer filled during the test!');
          }
        });

        if (this._rawPerflogPath && events.length) {
          fs.appendFileSync(this._rawPerflogPath, JSON.stringify(events));
        }
        return this._convertPerfRecordsToEvents(events);
      });

for (const {classPropertyName, transformType, isSignal} of meta.fields.inputs) {
  if (isSignal) {
    signalInputKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else if (!meta.coercedInputFields.has(classPropertyName)) {
    plainKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else {
    const propName = `ngAcceptInputType_${classPropertyName}`;
    const isUnsafe = isUnsafeObjectKey(classPropertyName);
    const access = isUnsafe ? `[${TcbExpr.quoteAndEscape(propName)}]` : `.${propName}`;
    const coercionType =
      transformType !== undefined ? transformType : `typeof ${typeRef}${access}`;

    coercedKeys.push(
      `${isUnsafe ? TcbExpr.quoteAndEscape(classPropertyName) : classPropertyName}: ${coercionType}`,
    );
  }
}

const result = [...syntacticDiagnostics, ...semanticDiagnostic, ...suggestionDiagnostics].map(
  (diagnostic) => {
    const lineAndCharacter =
      diagnostic.file && diagnostic.start
        ? diagnostic.file?.getLineAndCharacterOfPosition(diagnostic.start)
        : null;
    const from = diagnostic.start;
    const to = (diagnostic.start ?? 0) + (diagnostic.length ?? 0);

    return {
      from,
      to,
      message: ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n'),
      source: diagnostic.source,
      code: diagnostic.code,
      severity: ['warning', 'error', 'info'][diagnostic.category],
      ...(lineAndCharacter && {
        lineNumber: lineAndCharacter.line + 1,
        characterPosition: lineAndCharacter.character,
      }),
    };
  },
);

if (typeof providerRecord.provider === 'object') {
  if ((providerRecord.provider as ClassProvider).useClass !== undefined) {
    type = 'class';
  } else if ((providerRecord.provider as ValueProvider).useValue !== undefined) {
    type = 'value';
  } else if ((providerRecord.provider as FactoryProvider).useFactory !== undefined) {
    type = 'factory';
  } else if ((providerRecord.provider as ExistingProvider).useExisting !== undefined) {
    type = 'existing';
  }

  if (providerRecord.provider.multi !== undefined) {
    multi = providerRecord.provider.multi;
  }
} else if (typeof providerRecord.provider === 'function') {
  if (INTERNAL_TOKENS.includes((providerRecord.token as Type<any>).name)) {
    type = 'internal';
  }
}

this.displayedAreas.forEach((area) => {
  const areaSnapshot: IAreaSnapshot = {
    area,
    sizePixelAtStart: getElementPixelSize(area.component.elRef, direction),
    sizePercentAtStart: (untracked(this.unit) === 'percent' ? area.size : -1) as number, // If pixel mode, anyway, will not be used.
  };

  if (area.order < gutterOrder) {
    if (untracked(this.restrictMove)) {
      this.snapshot!.areasBeforeGutter = [areaSnapshot];
    } else {
      this.snapshot!.areasBeforeGutter.unshift(areaSnapshot);
    }
  } else if (area.order > gutterOrder) {
    if (untracked(this.restrictMove)) {
      if (this.snapshot!.areasAfterGutter.length === 0)
        this.snapshot!.areasAfterGutter = [areaSnapshot];
    } else {
      this.snapshot!.areasAfterGutter.push(areaSnapshot);
    }
  }
});

timelines.forEach(({keyframes}) => {
  const nonAnimatablePropsInitialValues = new Map<string, string | number>();
  keyframes.forEach((keyframe) => {
    const entriesToCheck = Array.from(keyframe.entries()).filter(
      ([prop]) => !allowedNonAnimatableProps.has(prop),
    );
    for (const [prop, value] of entriesToCheck) {
      if (!driver.validateAnimatableStyleProperty!(prop)) {
        if (nonAnimatablePropsInitialValues.has(prop) && !invalidNonAnimatableProps.has(prop)) {
          const propInitialValue = nonAnimatablePropsInitialValues.get(prop);
          if (propInitialValue !== value) {
            invalidNonAnimatableProps.add(prop);
          }
        } else {
          nonAnimatablePropsInitialValues.set(prop, value);
        }
      }
    }
  });
});

if (listeners && elementStates) {
  const visitedTriggers = new Set<string>();
  listeners.forEach((listener) => {
    const triggerName = listener.name;
    if (visitedTriggers.has(triggerName)) return;
    visitedTriggers.add(triggerName);

    const trigger = this._triggers.get(triggerName)!;
    const transition = trigger.fallbackTransition;
    const fromState = elementStates.get(triggerName) || DEFAULT_STATE_VALUE;
    const toState = new StateValue(VOID_VALUE);
    const player = new TransitionAnimationPlayer(this.id, triggerName, element);

    this._engine.totalQueuedPlayers++;
    this._queue.push({
      element,
      triggerName,
      transition,
      fromState,
      toState,
      player,
      isFallbackTransition: true,
    });
  });
}

if (completeSample.length >= this._sampleSize) {
  const latestSample = completeSample.slice(
    completeSample.length - this._sampleSize,
    completeSample.length,
  );
  const xValues: number[] = [];
  const yValues: number[] = [];
  for (let i = 0; i < latestSample.length; i++) {
    // For now, we only use the array index as x value.
    // TODO(tbosch): think about whether we should use time here instead
    xValues.push(i);
    yValues.push(latestSample[i].values[this._metric]);
  }
  const regressionSlope = Statistic.calculateRegressionSlope(
    xValues,
    Statistic.calculateMean(xValues),
    yValues,
    Statistic.calculateMean(yValues),
  );
  return regressionSlope >= 0 ? latestSample : null;
} else {
  return null;
}

if (
  !isCacheActive ||
  requestOptions === false ||
  // Do not cache requests sent with credentials.
  hasOutgoingCredentials(req) ||
  // POST requests are allowed either globally or at request level
  (requestMethod === 'POST' && !globalOptions.includePostRequests && !requestOptions) ||
  (requestMethod !== 'POST' && !ALLOWED_METHODS.includes(requestMethod)) ||
  // Do not cache requests with authentication or cookie headers unless explicitly enabled.
  (!globalOptions.includeRequestsWithAuthHeaders && hasAuthHeaders(req)) ||
  // Do not cache requests that explicitly forbid caching via Cache-Control
  // or Fetch API cache mode.
  hasUncacheableCacheControl(req.headers) ||
  isNonCacheableRequest(req.cache) ||
  globalOptions.filter?.(req) === false
) {
  return false;
}

return {
  getCurrentDirectory: () => basePath || ts.sys.getCurrentDirectory(),
  // We need to normalize the path separators here because by default, TypeScript
  // compiler hosts use posix canonical paths. In order to print consistent diagnostics,
  // we also normalize the paths.
  getCanonicalFileName: (fileName) => fileName.replace(/\\/g, '/'),
  getNewLine: () => {
    // Manually determine the proper new line string based on the passed compiler
    // options. There is no public TypeScript function that returns the corresponding
    // new line string. see: https://github.com/Microsoft/TypeScript/issues/29581
    if (options && options.newLine !== undefined) {
      return options.newLine === ts.NewLineKind.LineFeed ? '\n' : '\r\n';
    }
    return ts.sys.newLine;
  },
};

if (requiredBindings !== null && requiredBindings.size !== exposedRequiredBindings.size) {
  const missingBindings: string[] = [];

  for (const publicName of requiredBindings) {
    if (!exposedRequiredBindings.has(publicName)) {
      const name = existingBindings.getByClassPropertyName(publicName);

      if (name) {
        missingBindings.push(`'${name.bindingPropertyName}'`);
      }
    }
  }

  diagnostics.push(
    makeDiagnostic(
      ErrorCode.HOST_DIRECTIVE_MISSING_REQUIRED_BINDING,
      hostDirectiveMeta.directive.getOriginForDiagnostics(origin),
      `Required ${bindingType}${missingBindings.length === 1 ? '' : 's'} ${missingBindings.join(
        ', ',
      )} from host directive ${className} must be exposed.`,
    ),
  );
}

if (seen.has(block.name)) {
  const firstDecl = seen.get(block.name)!;
  this.diagnostics.push(
    makeTemplateDiagnostic(
      '' as TypeCheckId,
      this.sourceMapping,
      block.sourceSpan,
      ts.DiagnosticCategory.Error,
      ngErrorCode(ErrorCode.CONFLICTING_CONTENT_DECLARATION),
      `A @content block with the name '${block.name}' has already been defined for this ` +
        'component.',
      [
        {
          text: `The @content block '${block.name}' was first defined here.`,
          start: firstDecl.sourceSpan.start.offset,
          end: firstDecl.sourceSpan.end.offset,
          sourceFile: this.sourceMapping.node.getSourceFile(),
        },
      ],
    ),
  );
} else {
  seen.set(block.name, block);
}

if (selectorlessEnabled) {
  if (!metadata.isStandalone) {
    isPoisoned = true;
    diagnostics ??= [];
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.COMPONENT_NOT_STANDALONE,
        component.get('standalone') || node.name,
        `Cannot use selectorless with a component that is not standalone`,
      ),
    );
  } else if (rawImports || rawDeferredImports) {
    isPoisoned = true;
    diagnostics ??= [];
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.UNSUPPORTED_SELECTORLESS_COMPONENT_FIELD,
        (rawImports || rawDeferredImports)!,
        `Cannot use the "${rawImports === null ? 'deferredImports' : 'imports'}" field in a selectorless component`,
      ),
    );
  }
}

return initializer.properties.map((prop) => {
  if (!ts.isPropertyAssignment(prop) || !ts.isIdentifier(prop.name)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be a property assignment with a static name`,
    );
  }

  if (!ts.isNumericLiteral(prop.initializer) && !ts.isStringLiteralLike(prop.initializer)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be initialized to a number or string literal`,
    );
  }

  return {
    name: prop.name.text,
    type: `${declaration.name.getText()}.${prop.name.text}`,
    value: prop.initializer.getText(),
    memberType: MemberType.EnumItem,
    jsdocTags: extractJsDocTags(prop),
    description: extractJsDocDescription(prop),
    memberTags: [],
  };
});

if (ast.value.name === null) {
  if (ast.value.moduleName === null) {
    throw new Error('Invalid import without name nor moduleName');
  }
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: null,
    requestedFile: this.contextFile,
  });
} else if (ast.value.moduleName !== null) {
  // If a moduleName is specified, this is a normal import. If there's no module name, it's a
  // reference to a global/ambient symbol.
  // This is a normal import. Find the imported module.
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: ast.value.name,
    requestedFile: this.contextFile,
  });
} else {
  // The symbol is ambient, so just reference it.
  result = this.factory.createIdentifier(ast.value.name);
}

if (
  ts.isPropertyAccessExpression(node) &&
  node.expression.kind === ts.SyntaxKind.ThisKeyword &&
  // With the following we make sure we only flag invoked required initializers
  ts.isCallExpression(node.parent) &&
  node.parent.expression === node
) {
  const requiredProp = requiredInitializerDeclarations.find(
    (prop) => prop.name.getText() === node.name.getText(),
  );
  if (requiredProp) {
    const initializerFn = (
      requiredProp.initializer.expression as ts.PropertyAccessExpression
    ).expression.getText();
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.FORBIDDEN_REQUIRED_INITIALIZER_INVOCATION,
        node,
        `\`${node.name.getText()}\` is a required \`${initializerFn}\` and does not have a value in this context.`,
      ),
    );
  }
}

if (attrs) {
  for (let i = 0; i < attrs.length; i += 2) {
    const name = attrs[i];
    const value = attrs[i + 1];

    const terminalValuesMap = this._attrValueMap.get(name)!;
    if (value) {
      result =
        this._matchTerminal(terminalValuesMap, '', cssSelector, matchedCallback) || result;
    }
    result =
      this._matchTerminal(terminalValuesMap, value, cssSelector, matchedCallback) || result;

    const partialValuesMap = this._attrValuePartialMap.get(name)!;
    if (value) {
      result = this._matchPartial(partialValuesMap, '', cssSelector, matchedCallback) || result;
    }
    result =
      this._matchPartial(partialValuesMap, value, cssSelector, matchedCallback) || result;
  }
}

if (variable.name === null) {
  switch (variable.kind) {
    case ir.SemanticVariableKind.Context:
      variable.name = `ctx_r${state.index++}`;
      break;
    case ir.SemanticVariableKind.Identifier:
      // TODO: Prefix increment and `_r` are for compatibility with the old naming scheme.
      // This has the potential to cause collisions when `ctx` is the identifier, so we need a
      // special check for that as well.
      const compatPrefix = variable.identifier === CONTEXT_NAME ? 'i' : '';
      variable.name = `${variable.identifier}_${compatPrefix}r${++state.index}`;
      break;
    default:
      // TODO: Prefix increment for compatibility only.
      variable.name = `_r${++state.index}`;
      break;
  }
}

if (!dispatchResult && event.cancelable) {
  if (!event.abortController.signal.aborted) {
    event.abort(
      new DOMException('Navigation prevented by event.preventDefault()', 'AbortError'),
    );
  }
} else {
  if (precommitHandlers.length === 0) {
    commit();
  } else {
    const precommitController: NavigationPrecommitController = {redirect};
    const precommitPromisesList = precommitHandlers.map((handler) => {
      let p: Promise<void>;
      try {
        p = handler(precommitController);
      } catch (e) {
        p = Promise.reject(e);
      }
      p.catch(() => {});
      return p;
    });
    Promise.all(precommitPromisesList)
      .then(() => commit())
      .catch(processNavigateEventHandlerFailure);
  }
}

for (const node of nodes) {
  for (const input of node.inputs) {
    if (input.name === 'ngSwitchCase' && input.value) {
      if (!isNonNullishLiteralAST(input.value)) {
        return false;
      }
    }
  }

  if (node instanceof TmplAstTemplate) {
    for (const attr of node.templateAttrs) {
      if (attr instanceof TmplAstBoundAttribute && attr.name === 'ngSwitchCase' && attr.value) {
        if (!isNonNullishLiteralAST(attr.value)) {
          return false;
        }
      }
    }
  }

  const childHosts = node.children.filter(
    (child): child is TmplAstElement | TmplAstTemplate =>
      child instanceof TmplAstElement || child instanceof TmplAstTemplate,
  );

  if (!allNgSwitchCasesAreLiterals(childHosts)) {
    return false;
  }
}

return async (tree: Tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'nullishCoalescingNotNullable'],
      'suppress',
    );
    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'optionalChainNotNullable'],
      'suppress',
    );
  }
};

return async (tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    const angularOptions = getResolvedAngularCompilerOptions(tree, tsconfigPath);

    if (angularOptions['strictTemplates'] !== undefined) {
      continue;
    }

    if (json.get(['angularCompilerOptions', 'strictTemplates']) === undefined) {
      json.modify(['angularCompilerOptions', 'strictTemplates'], false);
    }
  }
};

try {
  const sourceFile = ts.createSourceFile(
    'temp.ts',
    `const obj = ${expr}`,
    ts.ScriptTarget.Latest,
    true,
  );

  const variableStatement = sourceFile.statements[0];
  if (!ts.isVariableStatement(variableStatement)) {
    return null;
  }

  const declaration = variableStatement.declarationList.declarations[0];
  if (!declaration.initializer || !ts.isObjectLiteralExpression(declaration.initializer)) {
    return null;
  }

  // Manage invalid syntax ngClass="{class1 class2}"
  const content = expr.slice(1, -1).trim();
  if (content && !content.includes(':') && content.includes(' ') && !content.includes(',')) {
    return null;
  }

  return declaration.initializer;
} catch (error) {
  return null;
}
